 * id
 * title
 * user_id
 * Description
 * url
 * status open closed bool
 * live on site
 * deadline
 * timestamps
 *
 */

foreach ($files as $f)
{
    $path = '';
    $url = '';

    if($f['type'] == 'pdf'){
        $path = $f['path'];
    }
    else {
        $url = $f['path'];
    }

    $state = $f['status'] == "Closed" ? 0 : 1;

    $data[] = ["path" => $path,
            "url" => $url,
            "type" => $f['type'],
            "title" => trim($f["title"]),
            "live" => 1,
            "status" => $state,
            "deadline" => trim($f['expiry']),
            ];

}

